// RUN: cuda-tile-translate -cudatilebc-to-mlir %S/Inputs/13.1/negi-op-13.1.tileirbc | FileCheck %s

// CHECK: entry @basic() {
// CHECK: %{{.*}} = constant <i32: [1, 2]> : tile<2xi32>
