void mlir::cuda_tile::registerTileIRBytecodeVersionOption() {
  // Register command line option.
  static llvm::cl::opt<BytecodeVersion, /*ExternalStorage=*/false,
                       BytecodeVersionParser>
      bytecodeVersion("bytecode-version",
